// Initialize async job for speaking practice
const inputData = $input.item.json.body || $input.item.json;
const audioBase64 = inputData.audio;
const referenceText = inputData.referenceText || '';
const language = inputData.language || 'en';

if (!audioBase64) {
  throw new Error('No audio provided. Please include audio (base64) in request body.');
}

const jobId = `speaking-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;
const staticData = $getWorkflowStaticData('global');
staticData[jobId] = { 
  status: 'processing', 
  createdAt: new Date().toISOString(),
  referenceText,
  language
};

return [{ 
  json: { 
    jobId, 
    audioBase64,
    referenceText,
    language
  } 
}];

// Prepare audio file from base64 for Groq API
const inputData = $input.item.json;
const audioBase64 = inputData.audioBase64;
const jobId = inputData.jobId;
const referenceText = inputData.referenceText;
const language = inputData.language;

// Remove data URL prefix if present
let cleanBase64 = audioBase64;
if (audioBase64.includes(',')) {
  cleanBase64 = audioBase64.split(',')[1];
}

// Convert base64 to binary buffer
const binaryData = Buffer.from(cleanBase64, 'base64');

return [{
  json: {
    jobId,
    referenceText,
    language
  },
  binary: {
    audioFile: {
      data: binaryData.toString('base64'),
      mimeType: 'audio/webm',
      fileName: 'recording.webm'
    }
  }
}];

// Extract transcript and prepare for LLM analysis
const groqResponse = $input.item.json;
const prepData = $('Prepare Audio').first().json;
const jobId = prepData.jobId;
const referenceText = prepData.referenceText;
const language = prepData.language;

const transcript = groqResponse.text || '';
const segments = groqResponse.segments || [];
const duration = groqResponse.duration || 0;

// Calculate word count and speaking rate
const wordCount = transcript.split(/\s+/).filter(w => w.length > 0).length;
const speakingRate = duration > 0 ? Math.round((wordCount / duration) * 60) : 0; // words per minute

return [{
  json: {
    jobId,
    transcript,
    referenceText,
    language,
    metrics: {
      duration: Math.round(duration * 10) / 10,
      wordCount,
      speakingRate,
      segmentCount: segments.length
    },
    segments
  }
}];

// Structure the final response
const llmResponse = $input.item.json;
const transcriptData = $('Process Transcript').first().json;
const jobId = transcriptData.jobId;

const feedback = llmResponse.message?.content || llmResponse.response || 'Analysis failed';

// Try to extract overall score from feedback
let overallScore = 0;
const scoreMatch = feedback.match(/\*\*OVERALL SCORE\*\*:\s*(\d+)/i);
if (scoreMatch) {
  overallScore = parseInt(scoreMatch[1], 10);
}

const result = {
  success: true,
  timestamp: new Date().toISOString(),
  jobId,
  transcript: transcriptData.transcript,
  referenceText: transcriptData.referenceText,
  metrics: transcriptData.metrics,
  analysis: {
    overallScore,
    feedback,
    model: 'gemma3:27b'
  }
};

// Save to static data
const staticData = $getWorkflowStaticData('global');
staticData[jobId] = {
  status: 'completed',
  result,
  completedAt: new Date().toISOString()
};

return [{ json: { ok: true, jobId } }];

// Check job status and return result if completed
const input = $input.item.json;
const jobId = (input.query && input.query.jobId) || (input.body && input.body.jobId) || input.jobId;

if (!jobId) {
  return [{ json: { success: true, status: 'alive', ping: true, timestamp: new Date().toISOString() } }];
}

const staticData = $getWorkflowStaticData('global');
const entry = staticData[jobId];

if (!entry) {
  return [{ json: { success: false, status: 'not_found', jobId, message: 'Job not found' } }];
}

if (entry.status === 'completed') {
  // Clean up old jobs (older than 10 minutes)
  const tenMinutesAgo = Date.now() - 10 * 60 * 1000;
  for (const key in staticData) {
    if (staticData[key].completedAt) {
      const completedTime = new Date(staticData[key].completedAt).getTime();
      if (completedTime < tenMinutesAgo) {
        delete staticData[key];
      }
    }
  }

  return [{ json: { success: true, status: 'completed', jobId, result: entry.result } }];
}

return [{ json: { success: true, status: 'processing', jobId, createdAt: entry.createdAt } }];
